class Solution:
    def medianOfUniquenessArray(self, nums) -> int:
        from collections import defaultdict
        n = len(nums)
        total = n * (n+1) // 2
        target = (total + 1) // 2

        def count_at_most_k(k):
            freq = defaultdict(int)
            left = 0
            cnt = 0
            for right in range(n):
                freq[nums[right]] += 1
                while len(freq) > k:
                    freq[nums[left]] -= 1
                    if freq[nums[left]] == 0:
                        del freq[nums[left]]
                    left += 1
                cnt += right - left + 1
            return cnt

        lo, hi = 1, n
        while lo < hi:
            mid = (lo + hi) // 2
            if count_at_most_k(mid) >= target:
                hi = mid
            else:
                lo = mid + 1
        return lo

