var medianOfUniquenessArray = function(nums) {
    const n = nums.length;
    const total = n * (n+1) / 2;
    const target = Math.ceil(total / 2);

    function countAtMostK(k) {
        const freq = new Map();
        let left = 0, cnt = 0;
        for (let right = 0; right < n; right++) {
            freq.set(nums[right], (freq.get(nums[right]) || 0) + 1);
            while (freq.size > k) {
                freq.set(nums[left], freq.get(nums[left]) - 1);
                if (freq.get(nums[left]) === 0) freq.delete(nums[left]);
                left++;
            }
            cnt += right - left + 1;
        }
        return cnt;
    }

    let lo = 1, hi = n;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (countAtMostK(mid) >= target) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
